var numberOfSpecialChars = function(word) {
    const lower = new Set();
    const upper = new Set();
    for (const c of word) {
        if (c >= 'a' && c <= 'z') lower.add(c);
        else upper.add(c.toLowerCase());
    }
    let count = 0;
    for (const c of lower) if (upper.has(c)) count++;
    return count;
};
